import{_ as o,o as t,c as i,ag as s}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"qiserver Setup Runbook","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/50_operations/20_qiserver/_index.md","filePath":"10_core/50_operations/20_qiserver/_index.md"}'),r={name:"10_core/50_operations/20_qiserver/_index.md"};function a(l,e,n,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="qiserver-setup-runbook" tabindex="-1">qiserver Setup Runbook <a class="header-anchor" href="#qiserver-setup-runbook" aria-label="Permalink to &quot;qiserver Setup Runbook&quot;">​</a></h1><p>This runbook serves as the operational manual for the <code>qiserver</code> node, capturing its current setup, configuration boundaries, and operational priorities.</p><h2 id="_1-runtime-path-doctrine" tabindex="-1">1. Runtime Path Doctrine <a class="header-anchor" href="#_1-runtime-path-doctrine" aria-label="Permalink to &quot;1. Runtime Path Doctrine&quot;">​</a></h2><ul><li><code>/srv/qios/repos</code>: For cloned Git repositories and active coding work.</li><li><code>/srv/qios/stacks</code>: For Docker Compose runtime stacks. <strong>Rule:</strong> Do not create nested Git repos inside stacks.</li><li><code>/srv/qios/data</code>: For persistent application data.</li></ul><h2 id="_2-current-installed-services-local-ports" tabindex="-1">2. Current Installed Services &amp; Local Ports <a class="header-anchor" href="#_2-current-installed-services-local-ports" aria-label="Permalink to &quot;2. Current Installed Services &amp; Local Ports&quot;">​</a></h2><p>All primary application services currently bind to <code>localhost</code> (<code>127.0.0.1</code>) only to prevent unintended exposure:</p><ul><li><strong>Paperless-ngx</strong>: <code>127.0.0.1:8010</code> (mapped to 8000 internally)</li><li><strong>NocoDB</strong>: <code>127.0.0.1:8088</code> (mapped to 8080 internally)</li><li><strong>Wiki.js</strong>: <code>127.0.0.1:3002</code> (mapped to 3000 internally). Verified internal/admin Tailscale Serve route: <code>https://qiserver-1.cerberus-sirius.ts.net:9448</code>. Acts as the readable knowledge base.</li><li><strong>Private Server Launcher (gethomepage)</strong>: <code>127.0.0.1:3001</code> (mapped to 3000 internally). <strong>Note:</strong> This is a local/tailnet utility only. Editing its <code>services.yaml</code> does not update the public <code>access.qially.com</code>.</li><li><strong>Portainer</strong>: <code>127.0.0.1:9443</code> (mapped to 9443 internally)</li><li><strong>Open WebUI</strong>: <code>127.0.0.1:3000</code> (mapped to 8080 internally)</li><li><strong>Neo4j</strong>: <code>127.0.0.1:7474</code>, <code>127.0.0.1:7687</code></li></ul><h2 id="_3-aider-and-ollama-setup-status" tabindex="-1">3. Aider and Ollama Setup Status <a class="header-anchor" href="#_3-aider-and-ollama-setup-status" aria-label="Permalink to &quot;3. Aider and Ollama Setup Status&quot;">​</a></h2><ul><li><strong>Ollama</strong>: Installed natively on qiserver and locked down to listen exclusively on <code>127.0.0.1:11434</code>.</li><li><strong>Aider</strong>: Installed under <code>/srv/qios/tools/aider</code>. <ul><li><strong>Rule:</strong> Aider should be used inside cloned repos under <code>/srv/qios/repos</code>, never directly inside live runtime stack folders.</li></ul></li><li><strong>Model Selection</strong>: <ul><li><code>qwen2.5-coder:3b</code> is the preferred interactive model for Aider.</li><li><code>qwen2.5-coder:7b</code> exists but is too heavy/slow for CPU-only interactive use.</li></ul></li></ul><h2 id="_4-exposure-security-concerns" tabindex="-1">4. Exposure &amp; Security Concerns <a class="header-anchor" href="#_4-exposure-security-concerns" aria-label="Permalink to &quot;4. Exposure &amp; Security Concerns&quot;">​</a></h2><ul><li><strong>Tailscale</strong>: Tailscale Serve correctly exposes Homepage, NocoDB, Open WebUI, and Wiki.js to the tailnet only.</li><li><strong>Wiki.js Public Route</strong>: <code>https://wiki.qially.com</code> currently returns Bad Gateway and should be treated as degraded until the Cloudflare tunnel route is repaired.</li><li><strong>Admin/Control Services</strong>: Must stay private/protected.</li><li><strong>Cockpit</strong>: <strong>WARNING</strong> - Currently listening broadly on <code>*:9090</code>. This requires immediate restriction.</li><li><strong>Legacy Paperless</strong>: A legacy compose file at <code>/home/qiadmin/docker-compose.yml</code> needs to be confirmed disabled/removed to prevent conflicts with the active stack at <code>/srv/qios/stacks/paperless</code>.</li></ul><h2 id="_5-paperless-ingestion-readiness-checklist" tabindex="-1">5. Paperless Ingestion Readiness Checklist <a class="header-anchor" href="#_5-paperless-ingestion-readiness-checklist" aria-label="Permalink to &quot;5. Paperless Ingestion Readiness Checklist&quot;">​</a></h2><ul><li><strong>Metadata First Rule</strong>: Paperless metadata (tags, document types, starter correspondents) must be fully configured before bulk import.</li><li><strong>Ingestion Testing Rule</strong>: Paperless should be tested with 10 diverse documents maximum (e.g., insurance, bills, legal) to tune the engine before any large or bulk ingestion occurs.</li></ul><h2 id="_6-what-is-done" tabindex="-1">6. What Is Done <a class="header-anchor" href="#_6-what-is-done" aria-label="Permalink to &quot;6. What Is Done&quot;">​</a></h2><ul><li>[x] Paperless stack is up and bound to localhost-only.</li><li>[x] NocoDB, Wiki.js, Homepage, Portainer, Open WebUI, and Neo4j stacks exist and are bound to localhost-only.</li><li>[x] Tailscale Serve is active and restricted to the tailnet.</li><li>[x] Ollama is installed and locked to <code>127.0.0.1:11434</code>.</li><li>[x] Aider is installed and configured.</li><li>[x] Repos/stacks/data path doctrine established.</li></ul><h2 id="_7-what-remains-next" tabindex="-1">7. What Remains Next <a class="header-anchor" href="#_7-what-remains-next" aria-label="Permalink to &quot;7. What Remains Next&quot;">​</a></h2><ul><li>[ ] Restrict Cockpit (<code>*:9090</code>) to private/protected access only.</li><li>[ ] Confirm, disable, or remove the legacy Paperless stack (<code>/home/qiadmin/docker-compose.yml</code>).</li><li>[ ] Verify <code>n8n</code> installation and status.</li><li>[ ] Configure Paperless metadata (types, tags, correspondents, Unknown Review rule).</li><li>[ ] Execute the 10-document Paperless ingestion test and tune results.</li><li>[ ] Create a robust backup script for <code>/srv/qios/stacks</code> and <code>/srv/qios/data</code>.</li><li>[ ] Complete the server exposure audit and write the <code>qs</code> status command script.</li></ul>',17)])])}const m=o(r,[["render",a]]);export{h as __pageData,m as default};
